import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { MapPin, Wifi, Flame, Droplet, Coffee, Car } from "lucide-react";
import { BentoGrid, BentoCard } from "@/components/BentoGrid";
import { formatCurrency } from "@/lib/utils";
import fs from "fs/promises";
import path from "path";

const facilityIcons: Record<string, React.ReactNode> = {
    "Perapian": <Flame size={16} className="text-primary dark:text-accent" />,
    "WiFi": <Wifi size={16} className="text-primary dark:text-accent" />,
    "Air Hangat": <Droplet size={16} className="text-primary dark:text-accent" />,
    "Dapur Mini": <Coffee size={16} className="text-primary dark:text-accent" />,
    "Parkir": <Car size={16} className="text-primary dark:text-accent" />
};

async function getCabinBySlug(slug: string) {
    const filePath = path.join(process.cwd(), "data", "cabins.json");
    const jsonData = await fs.readFile(filePath, "utf-8");
    const cabins = JSON.parse(jsonData);
    return cabins.find((c: any) => c.slug === slug) || null;
}

export default async function CabinDetailPage({ params }: { params: Promise<{ slug: string }> }) {
    const { slug } = await params;
    const cabin = await getCabinBySlug(slug);

    if (!cabin) {
        notFound();
    }

    return (
        <main className="min-h-screen bg-background pt-24 pb-32 md:pb-24">
            <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
                <BentoGrid>

                    {/* GALERI - Foto Utama Cabin */}
                    <BentoCard colSpan={2} rowSpan={2} className="relative overflow-hidden p-0 h-[400px] md:h-auto group">
                        <Image
                            src={cabin.foto_utama}
                            alt={cabin.nama}
                            fill
                            className="object-cover transition-transform duration-700 group-hover:scale-105"
                            priority
                        />
                    </BentoCard>

                    {/* GALERI - Foto Kecil 1 */}
                    <BentoCard colSpan={1} className="relative overflow-hidden p-0 h-[200px] md:h-auto group hidden md:block">
                        <Image
                            src={cabin.galeri[0]}
                            alt={`${cabin.nama} gallery 1`}
                            fill
                            className="object-cover transition-transform duration-500 group-hover:scale-110"
                        />
                    </BentoCard>

                    {/* GALERI - Foto Kecil 2 */}
                    <BentoCard colSpan={1} className="relative overflow-hidden p-0 h-[200px] md:h-auto group hidden md:block">
                        <Image
                            src={cabin.galeri[1] || cabin.galeri[0]}
                            alt={`${cabin.nama} gallery 2`}
                            fill
                            className="object-cover transition-transform duration-500 group-hover:scale-110"
                        />
                    </BentoCard>

                    {/* INFO UTAMA */}
                    <BentoCard colSpan={2} className="flex flex-col justify-center">
                        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                            <div>
                                <h1 className="text-3xl md:text-4xl font-black tracking-tight text-foreground mb-2">{cabin.nama}</h1>
                                <div className="flex items-center gap-2 text-neutral-500 font-medium">
                                    <span className="flex items-center gap-1 text-sm bg-accent/20 text-accent-content dark:text-accent px-2 py-0.5 rounded-full font-bold">
                                        ⭐ {cabin.rating}
                                    </span>
                                    <span>({cabin.ulasan} ulasan)</span>
                                </div>
                            </div>
                            <div className="text-left md:text-right bg-primary/5 dark:bg-slate-800 p-4 rounded-2xl">
                                <p className="text-sm text-neutral-500 font-medium mb-1">Mulai dari</p>
                                <p className="text-2xl font-black text-primary dark:text-accent">
                                    {formatCurrency(cabin.harga)}
                                    <span className="text-base font-normal text-neutral-500"> /malam</span>
                                </p>
                            </div>
                        </div>
                    </BentoCard>

                    {/* FASILITAS */}
                    <BentoCard colSpan={1} className="flex flex-col">
                        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                            <span className="bg-primary/10 text-primary dark:bg-accent/20 dark:text-accent p-2 rounded-lg">🌲</span>
                            Fasilitas Cabin
                        </h3>
                        <div className="grid grid-cols-2 gap-3">
                            {cabin.fasilitas_utama.map((fas: string, i: number) => (
                                <div key={i} className="flex items-center gap-2 text-sm font-medium text-neutral-700 dark:text-neutral-300">
                                    {facilityIcons[fas] || <span className="h-2 w-2 rounded-full bg-primary" />}
                                    {fas}
                                </div>
                            ))}
                        </div>
                    </BentoCard>

                    {/* LOKASI & DESKRIPSI */}
                    <BentoCard colSpan={2}>
                        <h3 className="text-lg font-bold mb-3">Tentang Cabin Ini</h3>
                        <p className="text-neutral-600 dark:text-neutral-400 leading-relaxed mb-6">
                            {cabin.deskripsi}
                        </p>

                        <div className="flex flex-col sm:flex-row items-center gap-4 bg-neutral-50 dark:bg-slate-900/50 p-4 rounded-2xl border border-neutral-100 dark:border-slate-800">
                            <div className="bg-primary/10 dark:bg-slate-800 p-3 rounded-full">
                                <MapPin className="text-primary dark:text-accent" size={24} />
                            </div>
                            <div className="flex-1 text-center sm:text-left">
                                <p className="font-bold text-foreground">Lokasi Cabin</p>
                                <p className="text-sm text-neutral-500">{cabin.lokasi}</p>
                            </div>
                            <a
                                href={cabin.koordinat}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="w-full sm:w-auto px-6 py-2.5 bg-white dark:bg-slate-800 text-primary dark:text-white font-bold rounded-xl border border-neutral-200 dark:border-slate-700 hover:bg-neutral-50 dark:hover:bg-slate-700 transition text-center"
                            >
                                Lihat Peta
                            </a>
                        </div>
                    </BentoCard>

                    {/* BOOKING CTA */}
                    <BentoCard colSpan={1} className="flex flex-col justify-center bg-gradient-to-br from-primary to-slate-800 text-white border-0">
                        <h3 className="text-xl font-bold mb-2">Ingin menginap di sini?</h3>
                        <p className="text-white/80 text-sm mb-6">Pesan sekarang untuk mendapatkan pengalaman menginap terbaik.</p>

                        <Link
                            href={`/booking/${cabin.slug}?type=cabin`}
                            className="w-full bg-accent text-neutral-900 font-black py-4 rounded-xl text-center hover:scale-[1.02] transition-transform shadow-xl"
                        >
                            Pesan Cabin Ini
                        </Link>
                    </BentoCard>

                </BentoGrid>
            </div>

            <div className="fixed bottom-0 left-0 w-full md:hidden bg-white dark:bg-slate-900 border-t border-neutral-200 dark:border-slate-800 p-4 flex items-center justify-between z-50">
                <div>
                    <p className="text-xs font-semibold text-neutral-500">Mulai dari</p>
                    <p className="text-xl font-black text-primary dark:text-accent">{formatCurrency(cabin.harga)}</p>
                </div>
                <Link
                    href={`/booking/${cabin.slug}?type=cabin`}
                    className="bg-primary dark:bg-accent text-white dark:text-neutral-900 font-bold px-8 py-3 rounded-xl"
                >
                    Pesan
                </Link>
            </div>
        </main>
    );
}

import { Navbar } from "@/components/Navbar";
import { SearchBar } from "@/components/SearchBar";
import { PromoBanner } from "@/components/PromoBanner";
import { CabinCard } from "@/components/CabinCard";
import { GridSkeleton } from "@/components/CardSkeleton";
import { Suspense } from "react";
import Image from "next/image";
import fs from "fs/promises";
import path from "path";

async function getCabins() {
    const filePath = path.join(process.cwd(), "data", "cabins.json");
    const jsonData = await fs.readFile(filePath, "utf-8");
    return JSON.parse(jsonData);
}

export default async function CabinListingPage() {
    const cabins = await getCabins();

    return (
        <main className="min-h-screen bg-background pb-20">
            <Navbar />

            {/* Hero Section */}
            <section className="relative h-[50vh] w-full bg-slate-900 overflow-hidden">
                <Image
                    src="https://images.unsplash.com/photo-1542314831-c6a4d14faaf2?auto=format&fit=crop&q=80&w=1920"
                    alt="Cabin Hero"
                    fill
                    priority
                    className="object-cover"
                />
                <div className="absolute inset-0 bg-primary/55 mix-blend-multiply" />

                <div className="absolute inset-0 flex flex-col items-center justify-center text-center px-4">
                    <h1 className="text-3xl font-black tracking-tight text-white md:text-5xl lg:text-6xl drop-shadow-lg">
                        Nikmati Malam di Cabin Hangat Dieng
                    </h1>
                    <p className="mt-4 text-sm font-medium text-white/90 md:text-lg">
                        Berpadu dengan alam, ditemani api unggun dan teh hangat.
                    </p>
                </div>

                {/* Floating Search Bar */}
                <SearchBar />
            </section>

            {/* Main Content */}
            <section className="mx-auto mt-20 max-w-7xl px-4 sm:px-6 lg:px-8 mt-24 md:mt-32">
                <PromoBanner text="EarlyBird: Menginap 2 malam gratis 1 malam!" />

                <div className="mt-12">
                    <h2 className="text-2xl font-bold text-foreground mb-6">Pilihan Cabin & Glamping</h2>
                    <Suspense fallback={<GridSkeleton />}>
                        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
                            {cabins.map((cabin: any) => (
                                <CabinCard key={cabin.id} {...cabin} />
                            ))}
                        </div>
                    </Suspense>
                </div>
            </section>
        </main>
    );
}

import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { MapPin, Clock, Users, CheckCircle2, ShieldAlert } from "lucide-react";
import { BentoGrid, BentoCard } from "@/components/BentoGrid";
import { formatCurrency } from "@/lib/utils";
import fs from "fs/promises";
import path from "path";

async function getJeepBySlug(slug: string) {
    const filePath = path.join(process.cwd(), "data", "jeeps.json");
    const jsonData = await fs.readFile(filePath, "utf-8");
    const jeeps = JSON.parse(jsonData);
    return jeeps.find((j: any) => j.slug === slug) || null;
}

export default async function JeepDetailPage({ params }: { params: Promise<{ slug: string }> }) {
    const { slug } = await params;
    const jeep = await getJeepBySlug(slug);

    if (!jeep) {
        notFound();
    }

    return (
        <main className="min-h-screen bg-background pt-24 pb-32 md:pb-24">
            <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
                <BentoGrid>

                    {/* GALERI - Foto Utama Jeep */}
                    <BentoCard colSpan={2} rowSpan={2} className="relative overflow-hidden p-0 h-[400px] md:h-auto group">
                        <Image
                            src={jeep.foto_utama}
                            alt={jeep.nama}
                            fill
                            className="object-cover transition-transform duration-700 group-hover:scale-105"
                            priority
                        />
                    </BentoCard>

                    {/* GALERI - Foto Kecil 1 */}
                    <BentoCard colSpan={1} className="relative overflow-hidden p-0 h-[200px] md:h-auto group hidden md:block">
                        <Image
                            src={jeep.galeri[0]}
                            alt={`${jeep.nama} gallery 1`}
                            fill
                            className="object-cover transition-transform duration-500 group-hover:scale-110"
                        />
                    </BentoCard>

                    {/* GALERI - Foto Kecil 2 */}
                    <BentoCard colSpan={1} className="relative overflow-hidden p-0 h-[200px] md:h-auto group hidden md:block">
                        <Image
                            src={jeep.galeri[1] || jeep.galeri[0]}
                            alt={`${jeep.nama} gallery 2`}
                            fill
                            className="object-cover transition-transform duration-500 group-hover:scale-110"
                        />
                    </BentoCard>

                    {/* NAMA PAKET & INFO UTAMA */}
                    <BentoCard colSpan={1} className="flex flex-col justify-center">
                        <h1 className="text-2xl font-black tracking-tight text-foreground mb-4 leading-snug">{jeep.nama}</h1>
                        <div className="flex flex-col gap-3">
                            <div className="flex items-center gap-2 text-neutral-600 dark:text-neutral-400 font-medium">
                                <Clock size={18} className="text-primary dark:text-accent" />
                                <span>Durasi: {jeep.durasi}</span>
                            </div>
                            <div className="flex items-center gap-2 text-neutral-600 dark:text-neutral-400 font-medium">
                                <Users size={18} className="text-primary dark:text-accent" />
                                <span>Maksimum {jeep.maks_orang} Orang</span>
                            </div>
                        </div>
                    </BentoCard>

                    {/* LIST DESTINASI */}
                    <BentoCard colSpan={1} className="flex flex-col">
                        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                            <span className="bg-primary/10 text-primary dark:bg-accent/20 dark:text-accent p-2 rounded-lg"><MapPin size={16} /></span>
                            Destinasi Wisata
                        </h3>
                        <ul className="flex flex-col gap-3">
                            {jeep.destinasi.map((dest: string, i: number) => (
                                <li key={i} className="flex items-start gap-2 text-sm font-medium text-neutral-700 dark:text-neutral-300">
                                    <div className="mt-1 h-1.5 w-1.5 rounded-full bg-accent shrink-0" />
                                    {dest}
                                </li>
                            ))}
                        </ul>
                    </BentoCard>

                    {/* ISI PAKET & KEBIJAKAN (Merged in row for Desktop) */}
                    <BentoCard colSpan={1} className="flex flex-col">
                        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                            <span className="bg-primary/10 text-primary dark:bg-accent/20 dark:text-accent p-2 rounded-lg"><CheckCircle2 size={16} /></span>
                            Isi Paket
                        </h3>
                        <ul className="flex flex-col gap-3">
                            {jeep.isi_paket.map((item: string, i: number) => (
                                <li key={i} className="flex items-center gap-2 text-sm text-neutral-600 dark:text-neutral-400">
                                    <span className="text-green-500">✓</span> {item}
                                </li>
                            ))}
                        </ul>
                    </BentoCard>

                    <BentoCard colSpan={2} className="flex flex-col">
                        <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-rose-600 dark:text-rose-400">
                            <span className="bg-rose-100 dark:bg-rose-900/30 p-2 rounded-lg"><ShieldAlert size={16} /></span>
                            Kebijakan & Syarat Ketentuan
                        </h3>
                        <ul className="flex flex-col gap-3 bg-rose-50/50 dark:bg-rose-900/10 p-4 rounded-xl border border-rose-100 dark:border-rose-900/30">
                            {jeep.kebijakan.map((item: string, i: number) => (
                                <li key={i} className="flex items-start gap-2 text-sm text-neutral-700 dark:text-neutral-300">
                                    <span className="text-rose-500 shrink-0">•</span> {item}
                                </li>
                            ))}
                        </ul>
                    </BentoCard>

                    {/* STICKY BOTTOM SECTION FOR DESKTOP IN BentoGrid */}
                    <BentoCard colSpan={1} className="flex flex-col justify-center bg-gradient-to-br from-primary to-slate-800 text-white border-0 hidden md:flex">
                        <h3 className="text-lg font-medium text-white/80 mb-1">Total Biaya Jeep</h3>
                        <p className="text-3xl font-black text-accent mb-6">
                            {formatCurrency(jeep.harga)}
                            <span className="text-sm font-normal text-white/70"> /jeep</span>
                        </p>

                        <p className="text-sm text-white/90 mb-4">Tentukan tanggal mainmu dan pesan sekarang!</p>
                        <div className="flex bg-white/10 rounded-xl p-3 mb-4 items-center justify-between cursor-pointer hover:bg-white/20 transition-colors">
                            <span className="text-sm font-medium">Pilih Tanggal</span>
                            <span className="text-xs bg-white text-primary px-2 py-1 rounded-md font-bold">Ubah</span>
                        </div>

                        <Link
                            href={`/booking/${jeep.slug}?type=jeep`}
                            className="w-full bg-accent text-neutral-900 font-black py-4 rounded-xl text-center hover:scale-[1.02] transition-transform shadow-xl"
                        >
                            Pesan Sekarang
                        </Link>
                    </BentoCard>

                </BentoGrid>
            </div>

            {/* Sticky Booking Bar for Mobile */}
            <div className="fixed bottom-0 left-0 w-full md:hidden bg-white dark:bg-slate-900 border-t border-neutral-200 dark:border-slate-800 p-4 flex flex-col gap-3 z-50">
                <div className="flex items-center justify-between">
                    <div>
                        <p className="text-xs font-semibold text-neutral-500">Harga per jeep</p>
                        <p className="text-xl font-black text-primary dark:text-accent">{formatCurrency(jeep.harga)}</p>
                    </div>
                    <Link
                        href={`/booking/${jeep.slug}?type=jeep`}
                        className="bg-primary dark:bg-accent text-white dark:text-neutral-900 font-bold px-8 py-3 rounded-xl"
                    >
                        Pesan
                    </Link>
                </div>
            </div>
        </main>
    );
}

import { Navbar } from "@/components/Navbar";
import { SearchBarJeep } from "@/components/SearchBarJeep";
import { PromoBanner } from "@/components/PromoBanner";
import { JeepCard } from "@/components/JeepCard";
import { GridSkeleton } from "@/components/CardSkeleton";
import { Suspense } from "react";
import Image from "next/image";
import fs from "fs/promises";
import path from "path";

async function getJeeps() {
    const filePath = path.join(process.cwd(), "data", "jeeps.json");
    const jsonData = await fs.readFile(filePath, "utf-8");
    return JSON.parse(jsonData);
}

export default async function JeepListingPage() {
    const jeeps = await getJeeps();

    return (
        <main className="min-h-screen bg-background pb-20">
            <Navbar />

            {/* Hero Section */}
            <section className="relative h-[50vh] w-full bg-slate-900 overflow-hidden">
                <Image
                    src="https://images.unsplash.com/photo-1533557554904-71be8ebf94f9?auto=format&fit=crop&q=80&w=1920"
                    alt="Jeep Adventure Hero"
                    fill
                    priority
                    className="object-cover"
                />
                <div className="absolute inset-0 bg-primary/55 mix-blend-multiply" />

                <div className="absolute inset-0 flex flex-col items-center justify-center text-center px-4">
                    <h1 className="text-3xl font-black tracking-tight text-white md:text-5xl lg:text-6xl drop-shadow-lg">
                        Jelajahi Dieng dengan Jeep Petualang
                    </h1>
                    <p className="mt-4 text-sm font-medium text-white/90 md:text-lg">
                        Taklukkan medan menantang dan nikmati keindahan alam secara private.
                    </p>
                </div>

                {/* Floating Search Bar (Khusus Jeep) */}
                <SearchBarJeep />
            </section>

            {/* Main Content */}
            <section className="mx-auto mt-20 max-w-7xl px-4 sm:px-6 lg:px-8 mt-24 md:mt-32">
                <PromoBanner text="Paket Sunrise Prau – Mulai 350K/orang!" />

                <div className="mt-12">
                    <h2 className="text-2xl font-bold text-foreground mb-6">Paket Sewa Jeep Tersedia</h2>
                    <Suspense fallback={<GridSkeleton />}>
                        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
                            {jeeps.map((jeep: any) => (
                                <JeepCard key={jeep.id} {...jeep} />
                            ))}
                        </div>
                    </Suspense>
                </div>
            </section>
        </main>
    );
}

import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { MapPin, Wifi, Tv, Droplet, Wind, Coffee, Flame, Car, ConciergeBell } from "lucide-react";
import { BentoGrid, BentoCard } from "@/components/BentoGrid";
import { formatCurrency } from "@/lib/utils";
import fs from "fs/promises";
import path from "path";

// Icon mapping helper (extended)
const facilityIcons: Record<string, React.ReactNode> = {
    "WiFi": <Wifi size={16} className="text-primary dark:text-accent" />,
    "TV": <Tv size={16} className="text-primary dark:text-accent" />,
    "Air Hangat": <Droplet size={16} className="text-primary dark:text-accent" />,
    "AC": <Wind size={16} className="text-primary dark:text-accent" />,
    "Dapur": <Coffee size={16} className="text-primary dark:text-accent" />,
    "Api Unggun": <Flame size={16} className="text-primary dark:text-accent" />,
    "Parkir": <Car size={16} className="text-primary dark:text-accent" />,
    "Resepsionis 24 Jam": <ConciergeBell size={16} className="text-primary dark:text-accent" />
};

async function getVillaBySlug(slug: string) {
    const filePath = path.join(process.cwd(), "data", "villas.json");
    const jsonData = await fs.readFile(filePath, "utf-8");
    const villas = JSON.parse(jsonData);
    return villas.find((v: any) => v.slug === slug) || null;
}

export default async function VillaDetailPage({ params }: { params: Promise<{ slug: string }> }) {
    const { slug } = await params;
    const villa = await getVillaBySlug(slug);

    if (!villa) {
        notFound();
    }

    return (
        <main className="min-h-screen bg-background pt-24 pb-32 md:pb-24">
            {/* Top Navigation Bar / Breadcrumb could go here */}

            <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
                <BentoGrid>

                    {/* GALERI - Foto Utama (Besar) */}
                    <BentoCard colSpan={2} rowSpan={2} className="relative overflow-hidden p-0 h-[400px] md:h-auto group">
                        <Image
                            src={villa.foto_utama}
                            alt={villa.nama}
                            fill
                            className="object-cover transition-transform duration-700 group-hover:scale-105"
                            priority
                        />
                    </BentoCard>

                    {/* GALERI - Foto Kecil 1 */}
                    <BentoCard colSpan={1} className="relative overflow-hidden p-0 h-[200px] md:h-auto group hidden md:block">
                        <Image
                            src={villa.galeri[0]}
                            alt={`${villa.nama} gallery 1`}
                            fill
                            className="object-cover transition-transform duration-500 group-hover:scale-110"
                        />
                    </BentoCard>

                    {/* GALERI - Foto Kecil 2 */}
                    <BentoCard colSpan={1} className="relative overflow-hidden p-0 h-[200px] md:h-auto group hidden md:block">
                        <Image
                            src={villa.galeri[1] || villa.galeri[0]}
                            alt={`${villa.nama} gallery 2`}
                            fill
                            className="object-cover transition-transform duration-500 group-hover:scale-110"
                        />
                        {villa.galeri.length > 2 && (
                            <div className="absolute inset-0 bg-black/40 flex items-center justify-center cursor-pointer hover:bg-black/50 transition-colors">
                                <span className="text-white font-bold text-xl">+{villa.galeri.length - 2} Foto</span>
                            </div>
                        )}
                    </BentoCard>

                    {/* INFO UTAMA */}
                    <BentoCard colSpan={2} className="flex flex-col justify-center">
                        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                            <div>
                                <h1 className="text-3xl md:text-4xl font-black tracking-tight text-foreground mb-2">{villa.nama}</h1>
                                <div className="flex items-center gap-2 text-neutral-500 font-medium">
                                    <span className="flex items-center gap-1 text-sm bg-accent/20 text-accent-content dark:text-accent px-2 py-0.5 rounded-full font-bold">
                                        ⭐ {villa.rating}
                                    </span>
                                    <span>({villa.ulasan} ulasan)</span>
                                </div>
